<template>
  <div class="task-item card" :class="{ 'task-completed': task.status === 'completed' }">
    <div class="task-body">
      <div class="task-main">
        <h3 class="task-title">{{ task.title }}</h3>
        <p v-if="task.description" class="task-desc">{{ task.description }}</p>
      </div>
      <div class="task-meta">
        <span class="badge" :class="'badge-' + task.status">{{ statusLabel }}</span>
        <span v-if="task.due_date" class="task-date">{{ task.due_date }}</span>
        <span v-if="currentUser?.isAdmin && task.user" class="task-owner">{{ task.user.email }}</span>
      </div>
      <div v-if="canModify" class="task-actions">
        <button class="btn btn-secondary btn-sm" @click="$emit('edit')">Edit</button>
        <button class="btn btn-danger btn-sm" @click="$emit('delete')">Delete</button>
      </div>
    </div>
  </div>
</template>

<script setup>
const props = defineProps({
  task: { type: Object, required: true },
  currentUser: { type: Object, default: null },
})

defineEmits(['edit', 'delete'])

const statusLabel = computed(() => ({
  pending: 'Pending',
  in_progress: 'In Progress',
  completed: 'Completed',
}[props.task.status]))

const canModify = computed(() => {
  if (!props.currentUser) return false
  if (props.currentUser.isAdmin) return true
  return props.currentUser.id === props.task.user_id
})
</script>

