.task-main { flex: 1; min-width: 200px; }
.task-title { font-size: 16px; font-weight: 600; margin-bottom: 4px; }
.task-desc { font-size: 13px; color: var(--color-text-secondary); line-height: 1.4; }
.task-meta { display: flex; align-items: center; gap: 10px; flex-wrap: wrap; }
.task-date { font-size: 12px; color: var(--color-text-secondary); }
.task-owner { font-size: 12px; color: var(--color-text-secondary); font-style: italic; }
